export async function analyzeJobDescription(input: string) {
  const parsedInput = jobDescriptionSchema.parse({ input });

  const aiResponse = await llmClient.generate(parsedInput);
  const normalizedResponse = skillMatrixSchema.safeParse(aiResponse);

  if (!normalizedResponse.success) {
    return { status: 'error', message: 'Invalid AI response' };
  }

  return {
    status: 'success',
    data: mapSkillMatrix(normalizedResponse.data),
  };
}
